    35→function relativeTime(iso: string | null): string {
    36→  if (!iso) return "";
    37→  const diff = Date.now() - new Date(iso).getTime();
    38→  const m = Math.floor(diff / 60000);
    39→  if (m < 1) return "Ahora";
    40→  if (m < 60) return `Hace ${m} min`;
    41→  const h = Math.floor(m / 60);
    42→  if (h < 24) return `Hace ${h}h`;
    43→  return `Hace ${Math.floor(h / 24)}d`;
    44→}
