function NavGroup({
  label,
  items,
  currentPath,
  isLight,
}: {
  label: string;
  items: readonly NavItem[];
  currentPath: string;
  isLight: boolean;
}) {
  const groupLabelColor = isLight ? "#A3A7AD" : "rgba(163,167,173,0.55)";

  return (
    <div className="px-3 mb-4">
      <div
        className="text-[10px] font-bold uppercase tracking-wider pl-3 mb-2"
        style={{ color: groupLabelColor }}
      >
        {label}
      </div>
      <nav className="space-y-0.5">
        {items.map((it) => {
          const isActive = it.to === "/app"
            ? currentPath === "/app"
            : currentPath.startsWith(it.to);
          return (
            <Link
              key={it.to}
              href={it.to}
              className={`flex items-center gap-3 w-full px-3 py-2 text-sm font-semibold rounded-lg transition-all no-underline ${
                isActive
                  ? isLight
                    ? "bg-blue-50 text-blue-700"
                    : "bg-cl-accent/10 text-cl-accent"
                  : isLight
                    ? "text-slate-600 hover:text-slate-900 hover:bg-slate-100"
                    : "text-cool-steel hover:text-white hover:bg-white/[0.08]"
              }`}
            >
              <i className={`ti ${it.icon} text-base`} /> {it.label}
            </Link>
          );
        })}
      </nav>
    </div>
  );
}

