import { type ReactNode, useState, useEffect } from "react";
import { Link, useLocation } from "wouter";
import { useAuth } from "@workspace/replit-auth-web";
import { useTheme } from "@/hooks/useTheme";

/* ─────────────── SIDEBAR — navegación funcional primaria ─────────────── */
const consoleNav = [
  { to: "/app",             label: "Panel General",        icon: "ti-layout-dashboard" },
  { to: "/app/agent",       label: "Configurar Agente IA", icon: "ti-robot" },
  { to: "/app/analytics",   label: "Analytics de Leads",   icon: "ti-chart-area-line" },
  { to: "/app/chat",        label: "Chat & RAG Trace",     icon: "ti-messages" },
  { to: "/app/flows",       label: "Flows",                icon: "ti-git-branch" },
] as const;

const operationsNav = [
  { to: "/app/appointments", label: "Agenda de Turnos",  icon: "ti-calendar-event" },
  { to: "/app/orders",       label: "Pedidos",            icon: "ti-shopping-bag" },
  { to: "/app/broadcast",    label: "Difusión Masiva",    icon: "ti-speakerphone" },
  { to: "/app/catalog",      label: "Catálogo Digital",   icon: "ti-layout-grid" },
] as const;

const builderNav = [
  { to: "/app/builder",     label: "Constructor de Apps",  icon: "ti-wand" },
  { to: "/app/forms",       label: "Formularios",          icon: "ti-forms" },
  { to: "/app/tables",      label: "Tablas",               icon: "ti-table" },
  { to: "/app/pages",       label: "Páginas",              icon: "ti-layout-2" },
  { to: "/app/automations", label: "Automatizaciones",     icon: "ti-bolt" },
] as const;

const businessNav = [
  { to: "/app/crm",        label: "CRM & Ventas",   icon: "ti-chart-bar" },
  { to: "/app/projects",   label: "Proyectos",       icon: "ti-layout-kanban" },
  { to: "/app/erp",        label: "ERP",             icon: "ti-building-factory" },
  { to: "/app/accounting", label: "Contabilidad",    icon: "ti-calculator" },
  { to: "/app/support",    label: "Soporte",         icon: "ti-ticket" },
  { to: "/app/rrhh",       label: "RRHH",            icon: "ti-id-badge" },
  { to: "/app/finanzas",   label: "Finanzas",        icon: "ti-trending-up" },
  { to: "/app/team",       label: "Equipo",          icon: "ti-users" },
] as const;

/* sección compacta al fondo del sidebar */
const resourcesNav = [
  { to: "/app/roi",       label: "Mi Ahorro ROI",         icon: "ti-trending-up" },
  { to: "/app/services",  label: "Mis Servicios",         icon: "ti-apps" },
  { to: "/app/knowledge", label: "Base de Conocimiento",  icon: "ti-file-text" },
  { to: "/app/mockups",   label: "Diseños",               icon: "ti-template" },
  { to: "/app/nosotros",  label: "Nosotros",              icon: "ti-building" },
  { to: "/app/casos",     label: "Casos de Éxito",        icon: "ti-star" },
  { to: "/app/checklist", label: "Checklist",             icon: "ti-checklist" },
  { to: "/app/research",  label: "Research",              icon: "ti-microscope" },
] as const;

/* ─────────────── HEADER — navegación secundaria ─────────────── */
const headerNav = [
  { to: "/app/cuenta",   label: "Mi Plan",     icon: "ti-credit-card" },
  { to: "/app/contacto", label: "Diagnóstico", icon: "ti-stethoscope" },
  { to: "/app/docs",     label: "Docs",        icon: "ti-book" },
] as const;

/* ─────────────── títulos de página ─────────────── */
const titles: Record<string, { title: string; subtitle: string }> = {
  "/app":               { title: "Panel de Control y Analíticas",        subtitle: "Monitoreo unificado de la suite de automatización Clientum" },
  "/app/agent":         { title: "Configurador de Agente IA",            subtitle: "Definí el perfil, catálogo y FAQs — simulá conversaciones en tiempo real" },
