function isAdmin(email: string | null | undefined) {
  if (!email) return false;
  if (email === "demo@clientum.com.ar") return false;
  return email.endsWith("@clientum.com.ar");
}

export function AppShell({ children }: { children: ReactNode }) {
  const [pathname] = useLocation();
  const meta = titles[pathname] ?? titles["/app"];
  const { user } = useAuth();
  const userIsAdmin = isAdmin(user?.email);
  useTheme();
  const [sessionExpired, setSessionExpired] = useState(false);

  useEffect(() => {
    const handler = () => setSessionExpired(true);
    window.addEventListener("session-expired", handler);
    return () => window.removeEventListener("session-expired", handler);
  }, []);

  function handleSignOut() {
    window.location.href = "/api/auth/logout";
  }

  const displayName = user?.firstName
    ? `${user.firstName}${user.lastName ? " " + user.lastName : ""}`
    : user?.email ?? "Usuario";

  return (
    <div className="grid grid-cols-[256px_1fr] w-screen h-screen overflow-hidden bg-[#DDDFE2]">

      {/* ═══════════════ SIDEBAR ═══════════════ */}
      <aside
        className="flex flex-col h-full py-5 select-none z-10 overflow-y-auto"
        style={{ background: "#031E43", borderRight: "1px solid rgba(59,80,109,0.4)" }}
      >
        {/* Logo */}
        <Link
          href="/"
          className="px-5 pb-5 flex items-center gap-3 no-underline flex-shrink-0"
          style={{ borderBottom: "1px solid rgba(59,80,109,0.4)", marginBottom: "1rem" }}
        >
          <div className="w-8 h-8 rounded-lg flex items-center justify-center" style={{ background: "#0A2558" }}>
            <svg viewBox="0 0 48 48" width="20" height="20" fill="none">
              <circle cx="24" cy="8" r="4.5" fill="white" />
              <circle cx="40" cy="24" r="4.5" fill="white" />
              <circle cx="24" cy="40" r="4.5" fill="white" />
              <circle cx="8" cy="24" r="4.5" fill="white" />
              <line x1="24" y1="8" x2="40" y2="24" stroke="white" strokeWidth="2.5" strokeLinecap="round" />
              <line x1="40" y1="24" x2="24" y2="40" stroke="white" strokeWidth="2.5" strokeLinecap="round" />
              <line x1="24" y1="40" x2="8" y2="24" stroke="white" strokeWidth="2.5" strokeLinecap="round" />
              <line x1="8" y1="24" x2="24" y2="8" stroke="white" strokeWidth="2.5" strokeLinecap="round" />
            </svg>
          </div>
          <span className="text-base font-extrabold tracking-tight text-white">Clientum</span>
        </Link>

        {/* Grupos funcionales principales */}
        <NavGroup label="Agente IA" items={consoleNav} currentPath={pathname} />
        <NavGroup label="Operaciones" items={operationsNav} currentPath={pathname} />
        <NavGroup label="Constructor" items={builderNav} currentPath={pathname} />
        <NavGroup label="Negocio" items={businessNav} currentPath={pathname} />

        {/* Admin (solo admins) */}
        {userIsAdmin && (
          <div className="px-3 mb-3">
            <nav className="space-y-0.5">
              <Link
                href="/app/admin"
                className={`flex items-center gap-3 w-full px-3 py-2 text-xs font-semibold rounded-lg transition-all no-underline ${
                  pathname.startsWith("/app/admin")
                    ? "bg-purple-500/20 text-purple-300"
                    : "text-purple-300/50 hover:text-purple-300 hover:bg-purple-500/10"
                }`}
              >
                <i className="ti ti-shield-lock text-sm" /> Panel Admin
              </Link>
            </nav>
          </div>
        )}

        {/* Recursos — sección compacta al fondo */}
        <div
          className="mt-auto px-3 pt-4 flex-shrink-0"
          style={{ borderTop: "1px solid rgba(59,80,109,0.4)" }}
        >
          <div
            className="text-[10px] font-bold uppercase tracking-wider pl-3 mb-2"
            style={{ color: "rgba(255,255,255,0.3)" }}
          >
            Recursos
          </div>
          <nav className="grid grid-cols-2 gap-0.5">
            {resourcesNav.map((it) => {
              const isActive = pathname.startsWith(it.to);
              return (
                <Link
                  key={it.to}
                  href={it.to}
                  className={`flex items-center gap-2 px-2 py-1.5 text-[11px] font-semibold rounded-md transition-all no-underline truncate ${
                    isActive
                      ? "bg-[#3B506D] text-white"
                      : "text-white/50 hover:text-white hover:bg-[#3B506D]/25"
                  }`}
                  title={it.label}
                >
                  <i className={`ti ${it.icon} text-sm flex-shrink-0`} />
                  <span className="truncate">{it.label}</span>
                </Link>
              );
            })}
          </nav>
        </div>
      </aside>

      {/* ═══════════════ MAIN ═══════════════ */}
      <main className="flex flex-col h-screen overflow-hidden">

        {/* ── HEADER con nav secundaria + usuario ── */}
        <header
          className="px-6 flex items-center justify-between flex-shrink-0"
          style={{
            background: "#FDFDFB",
            borderBottom: "1px solid #DDDFE2",
            minHeight: "56px",
          }}
        >
          {/* Título de la página */}
          <div className="min-w-0 mr-4">
            <h1 className="text-base font-bold leading-tight truncate" style={{ color: "#031E43" }}>
              {meta.title}
            </h1>
            <p className="text-[11px] leading-tight truncate" style={{ color: "#3B506D" }}>
              {meta.subtitle}
            </p>
          </div>

          {/* Nav secundaria + usuario */}
          <div className="flex items-center gap-1 flex-shrink-0">

            {/* Links secundarios */}
            {headerNav.map((it) => {
              const isActive = pathname.startsWith(it.to);
              return (
                <Link
                  key={it.to}
                  href={it.to}
                  className={`flex items-center gap-1.5 px-3 py-1.5 text-xs font-semibold rounded-lg transition-all no-underline ${
                    isActive
                      ? "bg-[#031E43] text-white"
                      : "text-[#3B506D] hover:text-[#031E43] hover:bg-[#DDDFE2]"
                  }`}
                >
                  <i className={`ti ${it.icon} text-sm`} />
                  {it.label}
                </Link>
              );
            })}

            {/* Admin header link */}
            {userIsAdmin && (
              <Link
                href="/app/admin"
                className={`flex items-center gap-1.5 px-3 py-1.5 text-xs font-semibold rounded-lg transition-all no-underline ${
                  pathname.startsWith("/app/admin")
                    ? "bg-purple-100 text-purple-700"
                    : "text-purple-500/70 hover:text-purple-700 hover:bg-purple-50"
                }`}
              >
                <i className="ti ti-shield-lock text-sm" />
                Admin
              </Link>
            )}

            {/* Separador */}
            <div className="w-px h-6 mx-2" style={{ background: "#DDDFE2" }} />

            {/* Usuario */}
            {user && (
              <div className="flex items-center gap-2">
                {user.profileImageUrl ? (
                  <img src={user.profileImageUrl} alt={displayName} className="w-7 h-7 rounded-full object-cover border border-[#DDDFE2]" />
                ) : (
                  <div className="w-7 h-7 bg-[#031E43] text-white rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0">
                    {displayName.charAt(0).toUpperCase()}
                  </div>
                )}
                <div className="hidden lg:block min-w-0">
                  <p className="text-xs font-semibold truncate max-w-[120px]" style={{ color: "#031E43" }}>{displayName}</p>
                  {user.email && (
                    <p className="text-[10px] truncate max-w-[120px]" style={{ color: "#3B506D" }}>{user.email}</p>
                  )}
                </div>
              </div>
            )}

            <button
              onClick={handleSignOut}
              title="Cerrar sesión"
              className="w-8 h-8 flex items-center justify-center rounded-lg transition-all text-[#3B506D] hover:text-[#031E43] hover:bg-[#DDDFE2]"
            >
              <i className="ti ti-logout text-base" />
            </button>
          </div>
        </header>

        {/* Contenido de la página */}
        <div className="flex-1 overflow-y-auto relative" style={{ background: "#FDFDFB" }}>
          {children}
        </div>

        {/* Sesión expirada */}
        {sessionExpired && (
          <div className="flex-shrink-0 flex items-center gap-4 px-6 py-3 bg-[#1a0a00] border-t border-amber-500/30 animate-in slide-in-from-bottom-2 duration-300">
            <div className="flex items-center gap-3 flex-1 min-w-0">
              <i className="ti ti-lock text-amber-400 text-lg flex-shrink-0" />
              <div className="min-w-0">
                <p className="text-sm font-bold text-amber-300 leading-tight">Sesión expirada</p>
                <p className="text-xs text-amber-400/70 leading-tight">Tu sesión cerró automáticamente. Iniciá sesión de nuevo para continuar.</p>
              </div>
            </div>
            <div className="flex items-center gap-2 flex-shrink-0">
              <a
                href="/api/login"
                className="inline-flex items-center gap-1.5 px-4 py-1.5 bg-amber-400 text-[#1a0a00] text-xs font-bold rounded-lg no-underline hover:bg-amber-300 transition-colors"
              >
                <i className="ti ti-login text-sm" />
                Iniciar sesión
              </a>
              <button
                onClick={() => setSessionExpired(false)}
                className="w-7 h-7 flex items-center justify-center text-amber-400/60 hover:text-amber-300 hover:bg-amber-400/10 rounded-lg transition-colors"
                title="Cerrar"
              >
                <i className="ti ti-x text-sm" />
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

/* ─────────────── NavGroup — sidebar ─────────────── */
type NavItem = { to: string; label: string; icon: string };

function NavGroup({
  label,
  items,
  currentPath,
}: {
  label: string;
  items: readonly NavItem[];
  currentPath: string;
}) {
  return (
    <div className="px-3 mb-3">
      <div
        className="text-[10px] font-bold uppercase tracking-wider pl-3 mb-1.5"
        style={{ color: "rgba(255,255,255,0.30)" }}
      >
        {label}
      </div>
      <nav className="space-y-0.5">
        {items.map((it) => {
          const isActive = it.to === "/app"
            ? currentPath === "/app"
            : currentPath.startsWith(it.to);
          return (
            <Link
              key={it.to}
              href={it.to}
              className={`flex items-center gap-3 w-full px-3 py-2 text-sm font-semibold rounded-lg transition-all no-underline ${
                isActive
                  ? "bg-[#3B506D] text-white"
                  : "text-white/60 hover:text-white hover:bg-[#3B506D]/30"
              }`}
            >
              <i className={`ti ${it.icon} text-base`} /> {it.label}
            </Link>
          );
        })}
      </nav>
    </div>
  );
}
